proof fn phi_1_always_unfold_intensional_bridge(ex: Execution<int>, p: TempPred<int>, i: nat)
    requires
        always(p).satisfied_by(ex),
    ensures
        p.satisfied_by(ex.suffix(i)),
{
    always_unfold::<int>(ex, p);
}

proof fn phi_4_always_lift_action_consecutive_chain(ex: Execution<int>, p: ActionPred<int>)
    requires
        always(lift_action(p)).satisfied_by(ex),
    ensures
        p(ex.head(), ex.head_next()),
        p(ex.head_next(), ex.suffix(2).head()),
{
    always_lift_action_unfold::<int>(ex, p);
}

